diff --git a/src/njs_vmcode.c b/src/njs_vmcode.c
index ec47865..bc5440f 100644
--- a/src/njs_vmcode.c
+++ b/src/njs_vmcode.c
@@ -797,8 +797,30 @@ next:
                 pnext = (njs_vmcode_prop_next_t *) pc;
                 retval = njs_scope_value(vm, pnext->retval);

+                /* Ensure the operand holds a DATA iterator value. */
+                if (njs_slow_path(!njs_is_data(value2, njs_make_tag(NJS_PROTO_ID_ANY)))) {
+                    /* Invalid iterator: return undefined and continue. */
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 next = value2->data.u.next;

+                /* Defensive checks for NULL pointers. */
+                if (njs_slow_path(next == NULL || next->array == NULL)) {
+                    if (next != NULL) {
+                        njs_mp_free(vm->mem_pool, next);
+                    }
+
+                    /* Mark the slot invalid to avoid reuse. */
+                    njs_set_invalid(value2);
+
+                    njs_set_undefined(retval);
+                    ret = sizeof(njs_vmcode_prop_next_t);
+                    break;
+                }
+
                 if (next->index < next->array->length) {
                     *retval = next->array->start[next->index++];

@@ -807,6 +829,7 @@ next:
                 }

                 njs_mp_free(vm->mem_pool, next);
+                njs_set_invalid(value2);

                 ret = sizeof(njs_vmcode_prop_next_t);
                 break;
@@ -1430,7 +1453,8 @@ njs_vmcode_property_foreach(njs_vm_t *vm, njs_value_t *object,
         return NJS_ERROR;
     }

-    vm->retval.data.u.next = next;
+    /* Initialize retval as a DATA value that holds the iterator state. */
+    njs_set_data(&vm->retval, next, njs_make_tag(NJS_PROTO_ID_ANY));

     code = (njs_vmcode_prop_foreach_t *) pc;

