diff --git a/src/class.c b/src/class.c
index ec9c648..351db5a 100644
--- a/src/class.c
+++ b/src/class.c
@@ -357,6 +357,9 @@ prepare_singleton_class(mrb_state *mrb, struct RBasic *o)
 {
   struct RClass *sc, *c;

+  /* Defensive checks: ensure object and its class pointer are valid. */
+  if (o == NULL || o->c == NULL) return;
+
   if (o->c->tt == MRB_TT_SCLASS) return;
   sc = MRB_OBJ_ALLOC(mrb, MRB_TT_SCLASS, mrb->class_class);
   sc->flags |= MRB_FL_CLASS_IS_INHERITED;
@@ -364,7 +367,7 @@ prepare_singleton_class(mrb_state *mrb, struct RBasic *o)
   sc->iv = 0;
   if (o->tt == MRB_TT_CLASS) {
     c = (struct RClass*)o;
-    if (!c->super) {
+    if (!c->super || c->super->c == NULL) {
       sc->super = mrb->class_class;
     }
     else {
@@ -373,13 +376,21 @@ prepare_singleton_class(mrb_state *mrb, struct RBasic *o)
   }
   else if (o->tt == MRB_TT_SCLASS) {
     c = (struct RClass*)o;
-    while (c->super->tt == MRB_TT_ICLASS)
+    /* Walk through ICLASS wrappers, but ensure super is valid while doing so. */
+    while (c->super && c->super->tt == MRB_TT_ICLASS)
       c = c->super;
-    make_metaclass(mrb, c->super);
-    sc->super = c->super->c;
+    if (!c->super) {
+      sc->super = mrb->class_class;
+    }
+    else {
+      make_metaclass(mrb, c->super);
+      sc->super = c->super->c ? c->super->c : mrb->class_class;
+    }
   }
   else {
     sc->super = o->c;
+    /* prepare_singleton_class might expect a valid RBasic; sc is valid.
+       No need to proceed if sc or its fields are invalid, but sc was just allocated. */
     prepare_singleton_class(mrb, (struct RBasic*)sc);
   }
   o->c = sc;

