diff --git a/programs/escape.c b/programs/escape.c
index 8a90741..20903e2 100644
--- a/programs/escape.c
+++ b/programs/escape.c
@@ -32,36 +32,66 @@ htmlescape (const char *restrict src, const int cp)
   if (!src)
     return NULL;
   len = strlen (src) + 10;
-  d = malloc (len);
+  dest = malloc (len);
+  if (!dest)
+    return NULL;
+  dest[0] = '\0';
+  d = dest;
   s = (unsigned char *)src;
-  dest = d;
-  while (*s++)
+  while (*s)
     {
+      unsigned char ch = *s++;
       const int off = d - dest;
-      if (off >= len - 8)
-        {
-          len += 10;
-          dest = realloc (dest, len);
-          d = dest + off;
-        }
-      switch (*s)
+      size_t esc_len = 0;
+      const char *esc = NULL;
+      char numbuf[32];
+
+      switch (ch)
         {
-        case '"': strcat (d, "&quot;"); d += 6; break;
-        case '\'': strcat (d, "&#39;"); d += 5; break;
-        case '`': strcat (d, "&#96;"); d += 5; break;
-        case '&': strcat (d, "&amp;"); d += 5; break;
-        case '<': strcat (d, "&lt;"); d += 4; break;
-        case '>': strcat (d, "&gt;"); d += 4; break;
-        case '{': strcat (d, "&#123;"); d += 6; break;
-        case '}': strcat (d, "&#125;"); d += 6; break;
+        case '"': esc = "&quot;"; esc_len = 6; break;
+        case '\'': esc = "&#39;"; esc_len = 5; break;
+        case '`': esc = "&#96;"; esc_len = 5; break;
+        case '&': esc = "&amp;"; esc_len = 5; break;
+        case '<': esc = "&lt;"; esc_len = 4; break;
+        case '>': esc = "&gt;"; esc_len = 4; break;
+        case '{': esc = "&#123;"; esc_len = 6; break;
+        case '}': esc = "&#125;"; esc_len = 6; break;
         default:
-          if (*s >= 127) // maybe encodings, no utf8 (see htmlwescape)
+          if (ch >= 127) /* maybe encodings, no utf8 (see htmlwescape) */
+            {
+              int n = snprintf (numbuf, sizeof(numbuf), "&#x%X;", ch);
+              if (n < 0)
+                { free (dest); return NULL; }
+              esc = numbuf;
+              esc_len = (size_t) n;
+            }
+          else if (ch >= 20)
             {
-              sprintf (d, "&#x%X;", *s); // 4 + 4
-              d += strlen (d);
+              esc = (const char *) &ch; /* will handle single byte below */
+              esc_len = 1;
             }
-          else if (*s >= 20)
-            *d++ = *s;
+        }
+
+      /* ensure capacity for esc_len bytes + terminating NUL */
+      if (off + (int)esc_len + 1 >= len)
+        {
+          int newlen = len;
+          while (off + (int)esc_len + 1 >= newlen)
+            newlen += 16;
+          char *newdest = realloc (dest, newlen);
+          if (!newdest)
+            { free (dest); return NULL; }
+          dest = newdest;
+          d = dest + off;
+          len = newlen;
+        }
+
+      if (esc && esc_len > 0)
+        {
+          /* esc may point inside numbuf or to a static string */
+          memcpy (d, esc, esc_len);
+          d += esc_len;
+          *d = '\0';
         }
     }
   *d = 0;
@@ -81,35 +111,66 @@ htmlwescape (BITCODE_TU wstr)
   while ((c = *tmp++))
     len++;
   len += 16;
-  d = dest = malloc (len);
+  dest = malloc (len);
+  if (!dest)
+    return NULL;
+  dest[0] = '\0';
+  d = dest;

-  while (*wstr++)
+  while (*wstr)
     {
+      BITCODE_RS ch = *wstr++;
       const int off = d - dest;
-      if (off >= len - 8)
-        {
-          len += 16;
-          dest = realloc (dest, len);
-          d = dest + off;
-        }
-      switch (*wstr)
+      size_t esc_len = 0;
+      const char *esc = NULL;
+      char numbuf[32];
+
+      switch (ch)
         {
-        case 34: strcat (d, "&quot;"); d += 6; break;
-        case 39: strcat (d, "&#39;"); d += 5; break;
-        case 38: strcat (d, "&amp;"); d += 5; break;
-        case 60: strcat (d, "&lt;"); d += 4; break;
-        case 62: strcat (d, "&gt;"); d += 4; break;
-        case 96: strcat (d, "&#96;"); d += 5; break;
-        case 123: strcat (d, "&#123;"

diff --git a/src/media_tools/av_parsers.c b/src/media_tools/av_parsers.c
