diff --git a/src/isomedia/box_funcs.c b/src/isomedia/box_funcs.c
index 98ff6bb..319dbf7 100644
--- a/src/isomedia/box_funcs.c
+++ b/src/isomedia/box_funcs.c
@@ -1950,6 +1950,14 @@ GF_Err gf_isom_box_write(GF_Box *a, GF_BitStream *bs)
 	//box has been disabled, do not write
 	if (!a->size) return GF_OK;

+	/* Validate that the pointer looks like a proper box with a registry before
+	   dereferencing it. This protects against malformed inputs where non-box
+	   data may be passed here. */
+	if (!a->registry) {
+		GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] Write invalid box type %s without registry\n", gf_4cc_to_str(a->type)));
+		return GF_ISOM_INVALID_FILE;
+	}
+
 	if (a->registry->disabled) {
 		GF_LOG(GF_LOG_DEBUG, GF_LOG_CONTAINER, ("[iso file] Box %s disabled registry, skip write\n", gf_4cc_to_str(a->type)));
 		return GF_OK;
@@ -1994,6 +2002,12 @@ GF_Err gf_isom_box_size(GF_Box *a)
 {
 	GF_Err e;
 	if (!a) return GF_BAD_PARAM;
+	/* Validate registry before dereferencing - callers must pass real GF_Box
+	   objects, but add a defensive check to avoid crashes on malformed files. */
+	if (!a->registry) {
+		GF_LOG(GF_LOG_ERROR, GF_LOG_CONTAINER, ("[iso file] Size invalid box type %s without registry\n", gf_4cc_to_str(a->type) ));
+		return GF_ISOM_INVALID_FILE;
+	}
 	if (a->registry->disabled) {
 		a->size = 0;
 		return GF_OK;
diff --git a/src/isomedia/isom_read.c b/src/isomedia/isom_read.c
index ba474c3..e08be82 100644
--- a/src/isomedia/isom_read.c
+++ b/src/isomedia/isom_read.c
@@ -5862,8 +5862,22 @@ Bool gf_isom_is_identical_sgpd(void *ptr1, void *ptr2, u32 grouping_type)
 	if (grouping_type) {
 		sgpd_write_entry(grouping_type, ptr1, bs1);
 	} else {
-		gf_isom_box_size((GF_Box *)ptr1);
-		gf_isom_box_write((GF_Box *)ptr1, bs1);
+		/* Ensure ptr1 is a GF_Box (has a registry) before calling box APIs.
+		   If it is not, the caller is passing a sample-group entry blob while
+		   claiming grouping_type==0 (box). In that case we must not call the
+		   box functions; return false to indicate they are not identical.
+		*/
+		if (!ptr1) {
+			gf_bs_del(bs1);
+			return GF_FALSE;
+		}
+		GF_Box *box1 = (GF_Box *)ptr1;
+		if (!box1->registry) {
+			gf_bs_del(bs1);
+			return GF_FALSE;
+		}
+		gf_isom_box_size(box1);
+		gf_isom_box_write(box1, bs1);
 	}
 	gf_bs_get_content(bs1, &buf1, &len1);
 	gf_bs_del(bs1);
@@ -5872,7 +5886,21 @@ Bool gf_isom_is_identical_sgpd(void *ptr1, void *ptr2, u32 grouping_type)
 	if (grouping_type) {
 		sgpd_write_entry(grouping_type, ptr2, bs2);
 	} else {
-		gf_isom_box_write((GF_Box *)ptr2, bs2);
