+			u32 available = dsi_size > 5 ? dsi_size - 5 : 0;
+			u32 copy_len = declared < available ? declared : available;
+			mpa->cfg_mha->mha_config = gf_malloc(sizeof(u8) * declared);
+			if (!mpa->cfg_mha->mha_config) return GF_OUT_OF_MEM;
+			/* copy only up to available bytes */
+			if (copy_len) memcpy(mpa->cfg_mha->mha_config, dsi+5, copy_len);
+			/* zero-pad the rest if declared is larger */
+			if (declared > copy_len) memset(mpa->cfg_mha->mha_config + copy_len, 0, declared - copy_len);
+			if (available != declared) {
+				GF_LOG(GF_LOG_WARNING, GF_LOG_CONTAINER, ("[ISO] MHA config size mismatch: declared=%u available=%u, truncated/zero-padded\n", declared, available));
+			}
+		} else {
+			mpa->cfg_mha->mha_config = NULL;
+		}
 	}
 	return GF_OK;
 }

